var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"거기! 위험하니까 엎드리세요!","JPN":"そこ！　危ないのでうつ伏せになってください！","ENG":"Hey, you! Get down!","TWN":"喂！危險，快趴下！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"파...... 파이어 볼!","JPN":"ファ……ファイヤボール！","ENG":"F-Fireball!","TWN":"火……火焰球！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"괜찮으세요? 다친 데는 없고요?","JPN":"大丈夫ですか？　怪我はありませんか？","ENG":"Are you alright? Not hurt or anything?","TWN":"妳沒事吧？沒有受傷吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아, 덕분에요. 보시는 대로 멀쩡하답니다.","JPN":"あ、おかげさまで助かりました。見てのとおり無事です。","ENG":"Oh, I'm fine. Thanks to you.","TWN":"多虧了你，我沒有受傷。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다행이다......","JPN":"よかった……","ENG":"Thank goodness...","TWN":"真是萬幸……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저쪽으로 가면 대피소가 있을 거예요. 침식체가 더 나타나기 전에 어서 가세요.","JPN":"あそこに行けば避難所があるはずです。侵食体がもっと現れる前に早く行ってください。","ENG":"You'll find a shelter over there. Please get to safety before more C.O.s appear.","TWN":"那邊有避難所，趁侵蝕體還沒出現，快去躲一躲吧。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"고마워요. 이 도시 분들은 다들 친절하네요.","JPN":"ありがとう。この都市の方々はみんな親切ですね。","ENG":"Thank you. Everyone in this city is so kind.","TWN":"謝謝，這個城市的人都很熱情。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그런데, 도와 주신 분의 이름은 어떻게 되시죠?","JPN":"ところで、私を助けてくださったあなたのお名前は？","ENG":"By the way, may I ask for your name?","TWN":"請問，您叫什麼名字？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 전 유나에요. 유나 스프링필드.","JPN":"あ、私はユナです。ユナ・スプリングフィールド。","ENG":"Oh, I'm Yuna. Yuna Springfield.","TWN":"啊，我叫尤娜。尤娜·斯普林菲爾德。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그래요? 스프링필드라......?","JPN":"そうですか。スプリングフィールド……？","ENG":"Oh? Springfield?","TWN":"這樣啊？斯普林菲爾德……？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"응? 혹시 절 아세요?","JPN":"ん？　もしかして、私を知ってるんですか？","ENG":"Huh? Do you know me?","TWN":"嗯？你認識我嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아뇨. 예전에 알던 분과 비슷한 이름이라서요.","JPN":"いいえ。知り合いの方と似たような名前だったので。","ENG":"No. Your name just reminds me of someone I once knew.","TWN":"不認識，只是名字跟我認識的人有點像。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그보다 전 대피소로 가기 어렵겠어요. 꼭 들러야 할 곳이 있거든요.","JPN":"それより、私は避難所には行けません。行かないといけない場所がありますから。","ENG":"Anyway, I'm afraid I won't be able to reach the shelter in time. There's a place I must stop by first.","TWN":"看來我不能去避難所了，因為我得去一個地方。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"위, 위험해요! 침식체가 어디 숨어 있을지 모르는데!","JPN":"あ、危ないですよ！　侵食体がどこに潜んでいるかわからないのに！","ENG":"B-but it's too dangerous! There's no telling where the C.O.s are hiding!","TWN":"太危險了！侵蝕體也不知道躲在哪裡！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"걱정은 고맙지만, 전 이번 할로윈 축제에 참가할 인형 퍼레이드의 책임자라서요.","JPN":"気持ちはありがたいのですが、私は今回のハロウィンに参加する人形パレードの責任者なんです。","ENG":"I appreciate your concern, but I'm in charge of the puppet parade for this Halloween festival.","TWN":"我知道妳在擔心什麼，但我是這次萬聖節慶典的木偶遊行表演的負責人。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"공연 준비를 하려면 제 인형들이 무사한지 확인해야 돼요.","JPN":"パレードの準備をするために私の人形たちが無事なのか確認しないと。","ENG":"I have to see if my puppets are okay if I want to prepare for the show.","TWN":"所以我得去查看我的木偶是否安全。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"인형 퍼레이드요......?","JPN":"人形パレードですか……？","ENG":"The puppet parade?","TWN":"木偶遊行表演……？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};